$$
\text{sgn}(x) =
\begin{cases}
-1 & \text{if } x < 0 \\
0 & \text{if } x = 0 \\
1 & \text{if } x > 0
\end{cases}
$$


$$
\text{copysign}(1.0,x) =
\begin{cases}
1.0  & \text{if } & \text{x } & \text{is} &\text{positive}, & \text{0.0} & or &\text{infinity} \\
-1.0 & \text{if } & \text{x } & \text{is} &\text{negative}, & \text{-0.0} & or &\text{neg.infinity}
\end{cases}
$$


$$
\large
\begin{cases}
x_{n+1} = y_n - \text{sgn}(x_n)\sqrt{|p x_n|}, \\
y_{n+1} = p - x_n.
\end{cases}
$$
